export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    if (request.method === "GET" && url.pathname === "/health") {
      const checks = await Promise.all([
        env.PROCESSOR.fetch("http://internal/health").then(r => r.json()),
        env.ANALYTICS.fetch("http://internal/health").then(r => r.json()),
        env.NOTIFICATIONS.fetch("http://internal/health").then(r => r.json()),
      ]);

      return json({
        service: "client-internal",
        ok: true,
        checks,
      });
    }

    if (request.method === "POST" && url.pathname === "/fanout") {
      let payload = {};
      try {
        payload = await request.json();
      } catch {}

      const [processor, analytics, notifications] = await Promise.all([
        env.PROCESSOR.fetch("http://internal/process", {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify(payload),
        }).then(r => r.json()),
        env.ANALYTICS.fetch("http://internal/track", {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({ eventType: "fanout", payload }),
        }).then(r => r.json()),
        env.NOTIFICATIONS.fetch("http://internal/send", {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({ channel: "email", payload }),
        }).then(r => r.json()),
      ]);

      return json({
        service: "client-internal",
        processor,
        analytics,
        notifications,
      });
    }

    return json({ error: "Not found", service: "client-internal" }, { status: 404 });
  },
};

